@Roles([RoleCode.ADMIN])
@Controller('topic/admin')
export class TopicAdminController {
  constructor(private readonly topicService: TopicService) {}

  @Post()
  async create(
    @Request() request: ProtectedRequest,
    @Body() createTopicDto: CreateTopicDto,
  ) {
    return await this.topicService.create(request.user, createTopicDto);
  }

  @Put('id/:id')
  async update(
    @Param('id', MongoIdTransformer) id: Types.ObjectId,
    @Request() request: ProtectedRequest,
    @Body() updateTopicDto: UpdateTopicDto,
  ) {
    return await this.topicService.update(request.user, id, updateTopicDto);
  }

  @Delete('id/:id')
  async delete(@Param('id', MongoIdTransformer) id: Types.ObjectId) {
    return await this.topicService.delete(id);
  }
}

import { ConfigModule } from '..';
import {
  AS_PROVIDER_METHOD_KEY,
  PARTIAL_CONFIGURATION_KEY,
  PARTIAL_CONFIGURATION_PROPNAME,
} from '../config.constants';
import { ConfigFactory } from '../interfaces';
import { ConfigObject } from '../types';
import { getConfigToken } from './get-config-token.util';

export interface ConfigFactoryKeyHost<T = unknown> {
  KEY: string | symbol;
  asProvider(): {
    imports: [ReturnType<typeof ConfigModule.forFeature>];
    useFactory: (config: T) => T;
    inject: [string | symbol];
  };
}

export function registerAs<
  TConfig extends ConfigObject,
  TFactory extends ConfigFactory = ConfigFactory<TConfig>,
>(
  token: string | symbol,
  configFactory: TFactory,
): TFactory & ConfigFactoryKeyHost<ReturnType<TFactory>> {
  const defineProperty = (key: string, value: unknown) => {
    Object.defineProperty(configFactory, key, {
      configurable: false,
      enumerable: false,
      value,
      writable: false,
    });
  };

  defineProperty(PARTIAL_CONFIGURATION_KEY, token);
  defineProperty(PARTIAL_CONFIGURATION_PROPNAME, getConfigToken(token));
  defineProperty(AS_PROVIDER_METHOD_KEY, () => ({
    imports: [ConfigModule.forFeature(configFactory)],
    useFactory: (config: unknown) => config,
    inject: [getConfigToken(token)],
  }));
  return configFactory as TFactory & ConfigFactoryKeyHost<ReturnType<TFactory>>;
}

import { registerAs } from '@nestjs/config';
import { AppConfig } from './app-config.type';
import validateConfig from '.././utils/validate-config';
import {
  IsEnum,
  IsInt,
  IsOptional,
  IsString,
  IsUrl,
  Max,
  Min,
} from 'class-validator';

enum Environment {
  Development = 'development',
  Production = 'production',
  Test = 'test',
}

class EnvironmentVariablesValidator {
  @IsEnum(Environment)
  @IsOptional()
  NODE_ENV: Environment;

  @IsInt()
  @Min(0)
  @Max(65535)
  @IsOptional()
  APP_PORT: number;

  @IsUrl({ require_tld: false })
  @IsOptional()
  FRONTEND_DOMAIN: string;

  @IsUrl({ require_tld: false })
  @IsOptional()
  BACKEND_DOMAIN: string;

  @IsString()
  @IsOptional()
  API_PREFIX: string;

  @IsString()
  @IsOptional()
  APP_FALLBACK_LANGUAGE: string;

  @IsString()
  @IsOptional()
  APP_HEADER_LANGUAGE: string;
}

export default registerAs<AppConfig>('app', () => {
  validateConfig(process.env, EnvironmentVariablesValidator);

  return {
    nodeEnv: process.env.NODE_ENV || 'development',
    name: process.env.APP_NAME || 'app',
    workingDirectory: process.env.PWD || process.cwd(),
    frontendDomain: process.env.FRONTEND_DOMAIN,
    backendDomain: process.env.BACKEND_DOMAIN ?? 'http://localhost',
    port: process.env.APP_PORT
      ? parseInt(process.env.APP_PORT, 10)
      : process.env.PORT
        ? parseInt(process.env.PORT, 10)
        : 3000,
    apiPrefix: process.env.API_PREFIX || 'api',
    fallbackLanguage: process.env.APP_FALLBACK_LANGUAGE || 'en',
    headerLanguage: process.env.APP_HEADER_LANGUAGE || 'x-custom-lang',
  };
});

import { registerAs } from '@nestjs/config';

import { IsEnum, IsString, ValidateIf } from 'class-validator';
import validateConfig from '../../utils/validate-config';
import { FileDriver, FileConfig } from './file-config.type';

class EnvironmentVariablesValidator {
  @IsEnum(FileDriver)
  FILE_DRIVER: FileDriver;

  @ValidateIf((envValues) =>
    [FileDriver.S3, FileDriver.S3_PRESIGNED].includes(envValues.FILE_DRIVER),
  )
  @IsString()
  ACCESS_KEY_ID: string;

  @ValidateIf((envValues) =>
    [FileDriver.S3, FileDriver.S3_PRESIGNED].includes(envValues.FILE_DRIVER),
  )
  @IsString()
  SECRET_ACCESS_KEY: string;

  @ValidateIf((envValues) =>
    [FileDriver.S3, FileDriver.S3_PRESIGNED].includes(envValues.FILE_DRIVER),
  )
  @IsString()
  AWS_DEFAULT_S3_BUCKET: string;

  @ValidateIf((envValues) =>
    [FileDriver.S3, FileDriver.S3_PRESIGNED].includes(envValues.FILE_DRIVER),
  )
  @IsString()
  AWS_S3_REGION: string;
}

export default registerAs<FileConfig>('file', () => {
  validateConfig(process.env, EnvironmentVariablesValidator);

  return {
    driver:
      (process.env.FILE_DRIVER as FileDriver | undefined) ?? FileDriver.LOCAL,
    accessKeyId: process.env.ACCESS_KEY_ID,
    secretAccessKey: process.env.SECRET_ACCESS_KEY,
    awsDefaultS3Bucket: process.env.AWS_DEFAULT_S3_BUCKET,
    awsS3Region: process.env.AWS_S3_REGION,
    maxFileSize: 5242880, // 5mb
  };
});

import { ApiProperty } from '@nestjs/swagger';
import { Allow } from 'class-validator';
import { Transform } from 'class-transformer';
import fileConfig from '../config/file.config';
import { FileConfig, FileDriver } from '../config/file-config.type';

import { GetObjectCommand, S3Client } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';
import { AppConfig } from '../../config/app-config.type';
import appConfig from '../../config/app.config';

export class FileType {
  @ApiProperty({
    type: String,
    example: 'cbcfa8b8-3a25-4adb-a9c6-e325f0d0f3ae',
  })
  @Allow()
  id: string;

  @ApiProperty({
    type: String,
    example: 'https://example.com/path/to/file.jpg',
  })
  @Transform(
    ({ value }) => {
      if ((fileConfig() as FileConfig).driver === FileDriver.LOCAL) {
        return (appConfig() as AppConfig).backendDomain + value;
      } else if (
        [FileDriver.S3_PRESIGNED, FileDriver.S3].includes(
          (fileConfig() as FileConfig).driver,
        )
      ) {
        const s3 = new S3Client({
          region: (fileConfig() as FileConfig).awsS3Region ?? '',
          credentials: {
            accessKeyId: (fileConfig() as FileConfig).accessKeyId ?? '',
            secretAccessKey: (fileConfig() as FileConfig).secretAccessKey ?? '',
          },
        });

        const command = new GetObjectCommand({
          Bucket: (fileConfig() as FileConfig).awsDefaultS3Bucket ?? '',
          Key: value,
        });

        return getSignedUrl(s3, command, { expiresIn: 3600 });
      }

      return value;
    },
    {
      toPlainOnly: true,
    },
  )
  path: string;
}

import { MiddlewareConsumer, Module, RequestMethod } from '@nestjs/common';
import { AppController } from './app.controller';

export const MIDDLEWARE_VALUE = 'middleware';
export const MIDDLEWARE_PARAM_VALUE = 'middleware_param';

@Module({
  controllers: [AppController],
})
export class AppModule {
  private count = 0;
  configure(consumer: MiddlewareConsumer) {
    consumer
      .apply((req, res, next) => res.end(MIDDLEWARE_VALUE))
      .forRoutes({ path: MIDDLEWARE_VALUE, method: RequestMethod.GET })
      .apply((req, res, next) => res.status(201).end(MIDDLEWARE_VALUE))
      .forRoutes({ path: MIDDLEWARE_VALUE, method: RequestMethod.POST })
      .apply((req, res, next) => res.end(MIDDLEWARE_PARAM_VALUE))
      .forRoutes({
        path: MIDDLEWARE_VALUE + '/*path',
        method: RequestMethod.GET,
      })
      .apply((req, res, next) => res.status(201).end(MIDDLEWARE_PARAM_VALUE))
      .forRoutes({
        path: MIDDLEWARE_VALUE + '/*path',
        method: RequestMethod.POST,
      })
      .apply((req, res, next) => {
        req.extras = { data: 'Data attached in middleware' };
        next();
      })
      .forRoutes({ path: '*path', method: RequestMethod.GET })
      .apply((req, res, next) => {
        req.middlewareParams = req.params;
        next();
      })
      .forRoutes({ path: '*path', method: RequestMethod.GET })
      .apply((req, res, next) => {
        this.count += 1;
        req.count = this.count;
        next();
      })
      .forRoutes('*path');
  }
}

import { ExecutionContext } from '@nestjs/common';
import { Type } from '@nestjs/common/interfaces';
import {
  ContextType,
  HttpArgumentsHost,
  RpcArgumentsHost,
  WsArgumentsHost,
} from '@nestjs/common/interfaces/features/arguments-host.interface';

export class ExecutionContextHost implements ExecutionContext {
  private contextType = 'http';

  constructor(
    private readonly args: any[],
    private readonly constructorRef: Type<any> | null = null,
    private readonly handler: Function | null = null,
  ) {}

  setType<TContext extends string = ContextType>(type: TContext) {
    type && (this.contextType = type);
  }

  getType<TContext extends string = ContextType>(): TContext {
    return this.contextType as TContext;
  }

  getClass<T = any>(): Type<T> {
    return this.constructorRef!;
  }

  getHandler(): Function {
    return this.handler!;
  }

  getArgs<T extends Array<any> = any[]>(): T {
    return this.args as T;
  }

  getArgByIndex<T = any>(index: number): T {
    return this.args[index] as T;
  }

  switchToRpc(): RpcArgumentsHost {
    return Object.assign(this, {
      getData: () => this.getArgByIndex(0),
      getContext: () => this.getArgByIndex(1),
    });
  }

  switchToHttp(): HttpArgumentsHost {
    return Object.assign(this, {
      getRequest: () => this.getArgByIndex(0),
      getResponse: () => this.getArgByIndex(1),
      getNext: () => this.getArgByIndex(2),
    });
  }

  switchToWs(): WsArgumentsHost {
    return Object.assign(this, {
      getClient: () => this.getArgByIndex(0),
      getData: () => this.getArgByIndex(1),
      getPattern: () => this.getArgByIndex(this.getArgs().length - 1),
    });
  }
}

import mongoose, { Model, UpdateWriteOpResult } from 'mongoose';
import { InjectModel } from '@nestjs/mongoose';
import { Injectable } from '@nestjs/common';
import { Chat } from './chat.schema';

@Injectable()
export class ChatService {
  constructor(@InjectModel(Chat.name) private chatModel: Model<Chat>) {}

  async create(chat: any): Promise<Chat> {
    return this.chatModel.create(chat);
  }

  async getMessages(
    sender: string,
    receiver: string,
    isAdmin = false,
  ): Promise<Chat[]> {
    let query = {};
    if (isAdmin) {
      query = {
        $or: [
          {
            sender,
          },
          { receiver },
        ],
      };
    } else if (sender && receiver) {
      query = {
        $or: [
          { sender, receiver },
          { sender: receiver, receiver: sender },
        ],
      };
    }
    return this.chatModel
      .find(query)
      .populate('sender')
      .populate('receiver')
      .sort({ createdAt: 1 })
      .exec();
  }

  async getMessageById(id: string): Promise<Chat> {
    return this.chatModel.findOne({ _id: id }).exec();
  }

  async updateState(
    chatId: string,
    state: number,
  ): Promise<UpdateWriteOpResult> {
    return this.chatModel
      .updateOne({ _id: new mongoose.mongo.ObjectId(chatId) }, { state })
      .exec();
  }

  async deleteMessage(chatId: string): Promise<mongoose.mongo.DeleteResult> {
    return this.chatModel
      .deleteOne({ _id: new mongoose.mongo.ObjectId(chatId) })
      .exec();
  }
}

import mongoose, { Model, UpdateWriteOpResult } from 'mongoose';
import { Injectable, NotFoundException } from '@nestjs/common';
import { Reply, ReplyDocument } from './schemas/reply.schema';
import { CreateReplyDto } from './dto/create-reply.dto';
import { InjectModel } from '@nestjs/mongoose';

@Injectable()
export class RepliesService {
  constructor(@InjectModel(Reply.name) private replyModel: Model<Reply>) {}

  async create(reply: CreateReplyDto): Promise<ReplyDocument> {
    return this.replyModel.create(reply);
  }

  async findAll(commentId: string): Promise<ReplyDocument[]> {
    return this.replyModel
      .find({ comment: commentId })
      .populate('owner', '_id username email firstName lastName')
      .exec();
  }

  async update(
    replyId: string,
    reply: Partial<ReplyDocument>,
  ): Promise<UpdateWriteOpResult> {
    return this.replyModel
      .updateOne({ _id: new mongoose.mongo.ObjectId(replyId) }, reply)
      .exec();
  }

  async remove(replyId: string): Promise<mongoose.mongo.DeleteResult> {
    return this.replyModel
      .deleteOne({ _id: new mongoose.mongo.ObjectId(replyId) })
      .exec();
  }

  async checkReplyOwner(replyId: string, owner: string): Promise<boolean> {
    const reply = await this.replyModel.findById(replyId).exec();
    if (!reply) throw new NotFoundException('Reply not found');
    return reply.owner.toString() === owner.toString();
  }

  async findRepliesByComment(commentId: string): Promise<ReplyDocument[]> {
    return this.replyModel
      .find({ comment: commentId })
      .populate('owner')
      .sort({ createdAt: 'desc' })
      .exec();
  }
}

import { EnumAuthTwoFactorMethod } from '@modules/auth/enums/auth.enum';
import { IsTwoFactorBackupCode } from '@modules/auth/validations/auth.two-factor-backup-code.validation';
import { IsTwoFactorCode } from '@modules/auth/validations/auth.two-factor-code.validation';
import { ApiProperty } from '@nestjs/swagger';
import { IsEnum, IsNotEmpty, IsString, ValidateIf } from 'class-validator';

export class UserLoginVerifyTwoFactorRequestDto {
    @ApiProperty({
        description:
            'Challenge token returned by the login endpoint when 2FA is required',
        example: 'c07c5f0d6d0c4c6db1f6a6d38f5ce8fa',
    })
    @IsString()
    @IsNotEmpty()
    challengeToken: string;

    @ApiProperty({
        description: 'Two-factor authentication method',
        example: EnumAuthTwoFactorMethod.code,
        enum: EnumAuthTwoFactorMethod,
    })
    @IsString()
    @IsNotEmpty()
    @IsEnum(EnumAuthTwoFactorMethod)
    method: EnumAuthTwoFactorMethod;

    @ApiProperty({
        description: `digit code from authenticator app. required if method is "${
            EnumAuthTwoFactorMethod.code
        }"`,
        example: '654321',
        required: false,
    })
    @ValidateIf(o => o.method === EnumAuthTwoFactorMethod.code)
    @IsString()
    @IsNotEmpty()
    @IsTwoFactorCode()
    code?: string;

    @ApiProperty({
        description: 'One-time backup code (will be consumed on success)',
        example: 'ABCD1234EF',
        required: false,
    })
    @ValidateIf(o => o.method === EnumAuthTwoFactorMethod.backupCodes)
    @IsString()
    @IsNotEmpty()
    @IsTwoFactorBackupCode()
    backupCode?: string;
}

